@app.delete("/api/docs/{doc_id}/comments/{comment_id}/replies/{reply_id}")
def delete_comment_reply(doc_id: str, comment_id: str, reply_id: str):
    """Delete a specific reply from a comment thread."""
    d = _require(doc_id)
