@app.get("/api/docs/{doc_id}/bullet-count-per-slide")
async def bullet_count_per_slide(doc_id: str):
    """Count bullet points per slide and flag slides exceeding the ideal limit."""
    IDEAL_MAX = 5
    d   = _require(doc_id)
